    }

    /// Creates a missing-file fact.
    pub fn missing(path: impl Into<PathBuf>) -> Self {
        Self::Missing(path.into())
    }

    /// Creates an unreadable-file fact.
    pub fn unreadable(path: impl Into<PathBuf>) -> Self {
        Self::Unreadable(path.into())
    }

