                operation.label()
            ),
        )
        .with_diagnostic(diagnostic)
    }

    /// Adds non-user-facing diagnostic text for logs or tests.
    pub fn with_diagnostic(mut self, diagnostic: impl Into<String>) -> Self {
        self.diagnostic = Some(diagnostic.into());
        self
