import zlib
TARGET = int('02445570', 16)
# Build linear system for 32 input bits of a 4-byte message. Python zlib.crc32
# is affine because of CRC init/final xor, so include zero-message offset.
def crc_for(x):
    return zlib.crc32(x.to_bytes(4, 'little')) & 0xffffffff
base = crc_for(0)
cols = []
for bit in range(32):
    cols.append(base ^ crc_for(1 << bit))
rhs = base ^ TARGET
# Gaussian elimination over GF(2), rows are output bits.
rows = []
for out_bit in range(32):
    mask = 0
    for in_bit, col in enumerate(cols):
        if (col >> out_bit) & 1:
            mask |= 1 << in_bit
    rows.append([mask, (rhs >> out_bit) & 1])
where = [-1] * 32
row = 0
for col in range(32):
    pivot = None
    for r in range(row, 32):
        if (rows[r][0] >> col) & 1:
            pivot = r
            break
    if pivot is None:
        continue
    rows[row], rows[pivot] = rows[pivot], rows[row]
    where[col] = row
    for r in range(32):
        if r != row and ((rows[r][0] >> col) & 1):
            rows[r][0] ^= rows[row][0]
            rows[r][1] ^= rows[row][1]
    row += 1
x = 0
for col, r in enumerate(where):
    if r != -1 and rows[r][1]:
        x |= 1 << col
b = x.to_bytes(4, 'little')
print(b.hex(), f'{zlib.crc32(b)&0xffffffff:08X}')

