        let fs = base_fs()
            .with_file("C:/Games/Fallout 4/Data/Fallout4.esm", module(0, MODULE_VERSION_100))
            .with_file("C:/Games/Fallout 4/Data/PluginA.esp", module(0, MODULE_VERSION_100))
            .with_file("C:/Games/Fallout 4/Data/PluginB.esl", module(0, MODULE_VERSION_100))
            .with_file("C:/Games/Fallout 4/Data/PluginB - voices_fr.ba2", ba2(8, b"DX10"))
            .with_file("C:/Games/Fallout 4/Data/Fallout4 - Startup.ba2", ba2(8, b"GNRL"))
            .with_file("C:/Games/Fallout 4/Data/Fallout4 - Nvflex.ba2", ba2(1, b"GNRL"));
        let process = FakeProcessInspector::default()
            .with_raw_version("C:/Games/Fallout 4/Fallout4.exe", "1.10.984.0");
        let missing_plugins_env = OverviewCollectionEnvironment::new()
            .with_plugins_txt("C:/Users/Example/AppData/Local/Fallout4/missing-plugins.txt");

        let facts = collect(&fs, &process, &install, &missing_plugins_env);

        assert!(matches!(
            facts.enablement.fallout4_ccc,
            OverviewFilePresence::Present(_)
        ));
        assert!(matches!(
            facts.enablement.plugins_txt,
            OverviewFilePresence::Missing(_)
        ));
        assert!(facts.modules.iter().all(|record| record.enabled));
        assert!(facts
